import { Breakpoints } from './debugger/break';
import * as wasm from './glue/pkg/glue';
import { Status } from './glue/pkg/glue';
export { Status };

async function fetchBytes(path: string): Promise<Uint8Array> {
  const resp = await fetch(path);
  if (!resp.ok) throw new Error(`failed to load ${path}`);
  return new Uint8Array(await resp.arrayBuffer());
}

/** A set of (pre)loaded files; a temporary hack until the emulator can load files itself. */
export type FileSet = Map<string, Uint8Array>;

/** Collapse `.`/`..`, lowercase, and use forward slashes.  Produces a `files`
 * map key with no leading slash (paths are relative to the served game root). */
function normalizePath(p: string): string {
  const out: string[] = [];
  for (const part of p.replace(/\\/g, '/').toLowerCase().split('/')) {
    if (part === '' || part === '.') continue;
    if (part === '..') {
      out.pop();
      continue;
    }
    out.push(part);
  }
  return out.join('/');
}

export async function fetchFileSet(files: string[], dir: string = ''): Promise<FileSet> {
  const fileset: FileSet = new Map();
  for (const file of files) {
    const path = dir + file;
    fileset.set(file.toLowerCase(), await fetchBytes(path));
  }
  return fileset;
}

class Window implements wasm.JsWindow {
  constructor(readonly host: Host, readonly hwnd: number) {
    const forward = (ev: Event) => {
      (ev as any).hwnd = hwnd;
      host.onEvent(ev);
    };
    // The guest reads mouse coordinates from `event.offsetX/offsetY`, which are
    // in CSS pixels of the *displayed* canvas.  When the canvas is scaled to fit
    // the screen (e.g. on phones) that no longer matches the guest's logical
    // 640x480 space, so clicks land in the wrong place.  Rescale to logical
    // coordinates and re-dispatch a corrected event (offsetX/offsetY are only
    // computed correctly once the event is dispatched to the canvas target).
    const stashEvent = (ev: MouseEvent) => {
      if ((ev as any).__rwFixed) {
        forward(ev);
        return false;
      }
      const rect = this.canvas.getBoundingClientRect();
      const [lw, lh] = this.size;
      if (!lw || !lh || !rect.width || !rect.height) {
        forward(ev); // Nothing to rescale yet; forward as-is.
        return false;
      }
      const fixed = new MouseEvent(ev.type, {
        button: ev.button,
        buttons: ev.buttons,
        clientX: rect.left + ((ev.clientX - rect.left) * lw) / rect.width,
        clientY: rect.top + ((ev.clientY - rect.top) * lh) / rect.height,
      });
      (fixed as any).__rwFixed = true;
      this.canvas.dispatchEvent(fixed);
      return false;
    };
    this.canvas.onmousedown = stashEvent;
    this.canvas.onmouseup = stashEvent;
    this.canvas.onmousemove = stashEvent;
    this.canvas.oncontextmenu = (ev) => {
      return false;
    };
  }

  title: string = '';
  canvas: HTMLCanvasElement = document.createElement('canvas');
  size: [number, number] = [0, 0];
  is_fullscreen = false;

  private reset_canvas() {
    const [w, h] = this.size;
    let scale = 1;
    if (this.is_fullscreen && w < 640) scale *= 2;

    // Note: the canvas must be sized to the size of physical pixels,
    // or else it will be scaled up with smoothing and pixels will be blurry.
    this.canvas.width = w * window.devicePixelRatio;
    this.canvas.height = h * window.devicePixelRatio;
    this.canvas.style.width = `${w * scale}px`;
    this.canvas.style.height = `${h * scale}px`;

    // The context scale seems preserved across calls to getContext, but then also
    // lost when the canvas is resized.  Rather than relying on this, always reset
    // and scale the context immediately on resize.
    const ctx = this.canvas.getContext('2d')!;
    ctx.reset();
    ctx.imageSmoothingEnabled = false;
    ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
    this.host.onWindowChanged();
  }

  set_size(w: number, h: number) {
    this.size = [w, h];
    this.reset_canvas();
  }

  fullscreen() {
    this.is_fullscreen = true;
    this.reset_canvas();
  }
}

class File implements wasm.JsFile {
  ofs = 0;

  /** `sink`, when present, persists the (possibly grown) buffer back to the
   * writable overlay after each write — used for the game's save/high-score
   * files.  Read-only game assets pass no sink and ignore writes. */
  constructor(readonly path: string, public bytes: Uint8Array, private sink?: (b: Uint8Array) => void) {
  }

  info(): number {
    return this.bytes.length;
  }

  seek(from: number, ofs: number): number {
    switch (from) {
      case 0: // start
        break;
      case 1: // end
        ofs = this.bytes.length + ofs;
        break;
      case 2: // cur
        ofs = this.ofs + ofs;
        break;
    }
    if (ofs < 0) {
      throw new Error(`seek out of bounds: ${from}:${ofs}`);
    }
    // Allow seeking past end (writes will extend the file).
    this.ofs = ofs;
    return ofs;
  }

  read(buf: Uint8Array): number {
    const n = Math.min(buf.length, this.bytes.length - this.ofs);
    if (n <= 0) return 0;
    buf.set(this.bytes.subarray(this.ofs, this.ofs + n));
    this.ofs += n;
    return n;
  }

  write(buf: Uint8Array): number {
    if (!this.sink) {
      console.warn('ignoring write to read-only', this.path);
      return buf.length;
    }
    const end = this.ofs + buf.length;
    if (end > this.bytes.length) {
      const grown = new Uint8Array(end);
      grown.set(this.bytes);
      this.bytes = grown;
    }
    this.bytes.set(buf, this.ofs);
    this.ofs = end;
    this.sink(this.bytes);
    return buf.length;
  }
}

/** Functions the emulator may need to call. */
export interface Host {
  onWindowChanged(): void;
  onError(msg: string): void;
  onStdOut(stdout: string): void;
  /** Notification that the emulator stopped, e.g. on blocking, error, or exit. */
  onStopped(status: Status): void;
  /** DOM event on an emulator surface; should be forwarded to emulator. */
  onEvent(event: Event): void;
}

/** Windows function calls, for debugging. */
export interface Trace {
  context: string;
  msg: string;
}

/** Wraps wasm.Emulator, providing the emulation=>web API. */
export class Emulator implements wasm.JsHost {
  readonly emu: wasm.Emulator;

  breakpoints: Breakpoints;
  looper: Looper;

  trace: Trace[] = [];
  events: Event[] = [];
  timer?: number;

  /** Virtual current working directory, used to resolve relative file paths.
   * The guest never really chdirs on the host; we track it here so paths like
   * "SOCCER98/details.dat" (after the game chdirs "..") resolve into `files`. */
  cwd: string;
  /** Web Audio output; created lazily on the first user gesture. */
  audioCtx?: AudioContext;
  /** AudioContext time up to which we've already scheduled samples. */
  audioNextTime = 0;
  /** In-memory writable overlay (keyed like the `files` map) for files the game
   * creates/writes at runtime — saves, high scores.  Kept separate from the
   * read-only fetched assets; persisted to localStorage so they survive reload. */
  writable = new Map<string, Uint8Array>();

  decoder = new TextDecoder();

  constructor(
    readonly host: Host,
    readonly files: FileSet,
    readonly storageKey: string,
    externalDLLs: string[],
    initialCwd: string = '',
  ) {
    this.cwd = normalizePath(initialCwd);
    this.emu = wasm.new_emulator(this);
    this.emu.set_external_dlls(externalDLLs);
    this.breakpoints = new Breakpoints(storageKey);
    this.looper = new Looper(this.runBatch);
    this.setupInput();
    this.loadWritable();
  }

  log(level: number, msg: string) {
    // TODO: surface this in the UI.
    switch (level) {
      case 1:
        console.error(msg);
        this.host.onError(msg);
        break;
      case 2:
        console.warn(msg);
        break;
      case 3:
        console.info(msg);
        break;
      case 4:
      case 5: // "trace"
        console.debug(msg);
        break;
      default:
        throw new Error(`unexpected log level #{level}`);
    }
  }

  win32_trace(context: string, msg: string) {
    this.trace.push({ context, msg });
  }

  ensure_timer(when: number): void {
    if (this.timer) {
      clearTimeout(this.timer);
    }
    const now = performance.now();
    console.log('timer for', when - now);
    const id = setTimeout(() => {
      if (this.timer !== id) {
        return;
      }
      this.timer = undefined;
      this.start();
    }, when - now);
    this.timer = id;
  }

  get_event(): Event | undefined {
    return this.events.shift();
  }

  open(path: string, options: wasm.FileOptions): wasm.JsFile | null {
    const key = this.resolve(path);
    const sink = (b: Uint8Array) => {
      this.writable.set(key, b);
      this.persistWritable(key, b);
    };
    // A previously written file, unless we're truncating it.
    if (this.writable.has(key) && !options.truncate) {
      return new File(path, this.writable.get(key)!, sink);
    }
    // Creating (or truncating) a writable file: saves, high scores.
    if (options.create || options.write || options.truncate) {
      let init = new Uint8Array();
      if (!options.truncate) {
        const ro = this.lookupReadonly(key);
        if (ro) init = ro.slice();
      }
      this.writable.set(key, init);
      this.persistWritable(key, init);
      return new File(path, this.writable.get(key)!, sink);
    }
    // Read-only fetched asset.
    const ro = this.lookupReadonly(key);
    if (!ro) {
      console.warn(`file not found: ${path} -> ${key}`);
      return null;
    }
    return new File(path, ro);
  }

  /** Resolve a read-only asset, honoring the Soccer98/pats symlink (accept the
   * file under either the game-relative or the top-level location). */
  private lookupReadonly(key: string): Uint8Array | undefined {
    let bytes = this.files.get(key);
    if (!bytes && key.startsWith('soccer98/')) {
      bytes = this.files.get(key.slice('soccer98/'.length));
    }
    if (!bytes) {
      bytes = this.files.get('soccer98/' + key);
    }
    return bytes;
  }

  remove_file(path: string) {
    const key = this.resolve(path);
    this.writable.delete(key);
    try {
      localStorage.removeItem('rw:' + this.storageKey + ':' + key);
    } catch {}
  }

  private persistWritable(key: string, bytes: Uint8Array) {
    // Best-effort persistence of small save files across reloads.
    try {
      if (bytes.length <= 256 * 1024) {
        let s = '';
        for (let i = 0; i < bytes.length; i++) s += String.fromCharCode(bytes[i]);
        localStorage.setItem('rw:' + this.storageKey + ':' + key, btoa(s));
      }
    } catch {}
  }

  private loadWritable() {
    try {
      const prefix = 'rw:' + this.storageKey + ':';
      for (let i = 0; i < localStorage.length; i++) {
        const k = localStorage.key(i)!;
        if (!k.startsWith(prefix)) continue;
        const bin = atob(localStorage.getItem(k)!);
        const bytes = new Uint8Array(bin.length);
        for (let j = 0; j < bin.length; j++) bytes[j] = bin.charCodeAt(j);
        this.writable.set(k.slice(prefix.length), bytes);
      }
    } catch {}
  }

  /** Resolve a guest path (relative to the virtual cwd) to a `files` map key:
   * lowercased, forward slashes, drive letter stripped, `.`/`..` collapsed. */
  resolve(path: string): string {
    let p = path.replace(/\\/g, '/').toLowerCase().replace(/^[a-z]:/, '');
    if (!p.startsWith('/')) {
      p = (this.cwd ? this.cwd + '/' : '') + p;
    }
    return normalizePath(p);
  }

  set_current_dir(path: string) {
    this.cwd = this.resolve(path);
  }

  current_dir(): string {
    return 'Z:\\' + this.cwd.replace(/\//g, '\\');
  }

  stdout(buf: Uint8Array) {
    const text = this.decoder.decode(buf);
    this.host.onStdOut(text);
  }

  windows: Window[] = [];
  create_window(hwnd: number): wasm.JsWindow {
    let window = new Window(this.host, hwnd);
    this.windows.push(window);
    this.host.onWindowChanged();
    return window;
  }

  screen() {
    // XXX how to tie surface and window together?
    // The DirectDraw calls SetCooperativeLevel() on the hwnd, and then CreateSurface with primary,
    // but how to plumb that info across JS boundary?
    return this.windows[this.windows.length - 1].canvas.getContext('2d')!;
  }

  /** Called from wasm (dsound mixer) with one chunk of i16 mono @44100Hz.
   * Schedules it onto the Web Audio clock, right after the previous chunk. */
  audio(buf: Int16Array) {
    const ctx = this.audioCtx;
    if (!ctx) return;
    const frames = buf.length;
    if (frames === 0) return;
    const ab = ctx.createBuffer(1, frames, 44100);
    const ch = ab.getChannelData(0);
    for (let i = 0; i < frames; i++) {
      ch[i] = buf[i] / 32768;
    }
    const src = ctx.createBufferSource();
    src.buffer = ab;
    src.connect(ctx.destination);
    const t = Math.max(this.audioNextTime, ctx.currentTime);
    src.start(t);
    this.audioNextTime = t + frames / 44100;
  }

  /** Create the AudioContext (once).  Must be called from a user gesture, else
   * the browser starts it suspended; we resume() on every gesture too. */
  private ensureAudioCtx() {
    if (!this.audioCtx) {
      const Ctor = window.AudioContext ?? (window as any).webkitAudioContext;
      if (!Ctor) return;
      this.audioCtx = new Ctor({ sampleRate: 44100 });
      this.audioNextTime = 0;
    }
    if (this.audioCtx.state === 'suspended') {
      this.audioCtx.resume();
    }
  }

  /** Produce audio chunks until ~0.2s is queued ahead of the playback clock.
   * Paces mixer output to real time (JS side, since wasm is single-threaded and
   * can't be driven by an audio-thread callback).  Called after each CPU batch. */
  private pumpAudio() {
    const ctx = this.audioCtx;
    if (!ctx || ctx.state !== 'running') return;
    const AHEAD = 0.2;
    let guard = 0;
    while (this.audioNextTime < ctx.currentTime + AHEAD && guard++ < 16) {
      this.emu.pump_audio();
    }
  }

  /** Wire keyboard input and unlock audio.  Keyboard events go to `window`
   * (the canvas isn't focusable) and are tagged with the current window's hwnd,
   * mirroring the mouse-event path. */
  private setupInput() {
    const onKey = (ev: KeyboardEvent) => {
      this.ensureAudioCtx();
      const win = this.windows[this.windows.length - 1];
      if (!win) return;
      // Suppress browser defaults for keys the game uses that would otherwise
      // scroll the page or move focus.
      switch (ev.code) {
        case 'Space':
        case 'Tab':
        case 'Slash':
        case 'ArrowUp':
        case 'ArrowDown':
        case 'ArrowLeft':
        case 'ArrowRight':
          ev.preventDefault();
          break;
      }
      if (ev.repeat) return; // DirectInput wants edges, not auto-repeat.
      (ev as any).hwnd = win.hwnd;
      this.enqueueEvent(ev);
    };
    window.addEventListener('keydown', onKey);
    window.addEventListener('keyup', onKey);
    window.addEventListener('mousedown', () => this.ensureAudioCtx());
  }

  startExe(cmdLine: string, relocate: boolean) {
    this.emu.start_exe(cmdLine, relocate);
  }

  step() {
    this.emu.unblock(); // Attempt to resume any blocked threads.
    this.emu.run(1);
  }

  private runBatch = (stepSize: number): number | null => {
    const startSteps = this.emu.instr_count;
    const cpuState = this.emu.run(stepSize) as wasm.Status;
    const endSteps = this.emu.instr_count;

    this.pumpAudio();

    if (cpuState !== wasm.Status.Running) {
      this.breakpoints.uninstall(this.emu);
      this.looper.stop();
      this.host.onStopped(cpuState);
      return null;
    }

    const steps = endSteps - startSteps;
    return steps;
  };

  start() {
    if (this.looper.running) return;
    this.emu.unblock(); // Attempt to resume any blocked threads.
    // Advance past the current breakpoint, if any.
    if (this.breakpoints.isAtBreakpoint(this.emu.cpu().eip)) {
      this.step();
    }
    this.breakpoints.install(this.emu);
    this.looper.start();
  }

  stop() {
    this.looper.stop();
  }

  enqueueEvent(event: Event) {
    this.events.push(event);
    this.start();
  }

  mappings(): wasm.Mapping[] {
    return JSON.parse(this.emu.mappings_json()) as wasm.Mapping[];
  }

  labels(): Array<[number, string]> {
    const obj = JSON.parse(this.emu.labels()) as Record<number, string>;
    return Object.entries(obj).map(([addr, label]) => [parseInt(addr, 10), label]);
  }

  disassemble(addr: number): wasm.Instruction[] {
    // Note: disassemble_json() may cause allocations, invalidating any existing .memory()!
    return JSON.parse(this.emu.disassemble_json(addr, 20)) as wasm.Instruction[];
  }
}

/** Target milliseconds to execute per batch. */
const TARGET_MS = 8;

/** Runs blocking code (emulation) while yielding to to the browser event loop. */
class Looper {
  channel = new MessageChannel();

  running = false;

  /** Number of steps to execute per stepMany, adjusted dynamically. */
  stepSize = 5000;
  /** Moving average of steps executed per millisecond. */
  stepsPerMs = 0;

  constructor(private loopee: (count: number) => number | null) {
    this.channel.port2.onmessage = () => this.loop();
  }

  /** Main "loop" that loops asynchronously by posting to the internal message channel. */
  private loop() {
    if (!this.running) return;
    const keepGoing = this.runBatch();
    if (!keepGoing) {
      this.stop();
    } else {
      this.channel.port1.postMessage(null);
    }
  }

  /** Runs one batch of steps, measuring and adjusting parameters to hit this.targetMs. */
  private runBatch(): boolean {
    const startTime = performance.now();
    const steps = this.loopee(this.stepSize);
    const endTime = performance.now();

    if (steps === null) {
      return false;
    }

    const deltaTime = endTime - startTime;
    if (steps > 1000 && deltaTime > 0) { // only update if we ran enough instructions to get a good measurement
      const stepsPerMs = steps / deltaTime;
      const alpha = 0.5; // smoothing factor
      this.stepsPerMs = alpha * stepsPerMs + (1 - alpha) * this.stepsPerMs;

      if (deltaTime < TARGET_MS) {
        this.stepSize = Math.round(this.stepsPerMs * TARGET_MS);
        // console.log(`${steps} instructions in ${deltaTime.toFixed(0)}ms; adjusted step rate: ${this.stepSize}`);
      }
    }

    return true;
  }

  start() {
    if (this.running) return;
    this.running = true;
    this.channel.port1.postMessage(null);
  }

  stop() {
    this.running = false;
  }
}

interface URLParams {
  /** URL directory that all other paths are resolved relative to. */
  dir?: string;
  /** Command line to run. */
  cmdLine: string;
  /** DLLs to load from files instead of builtin implementations. */
  externalDLLs: string[];
  /** Files to load.  TODO: we should fetch these dynamically instead. */
  files: string[];
  /** If true, relocate the exe on load. */
  relocate?: boolean;
}

function parseURL(): URLParams | undefined {
  const query = new URLSearchParams(document.location.search);
  const files = query.getAll('file');
  const dir = query.get('dir') || undefined;
  const cmdLine = query.get('cmdline') || files[0];
  const exe = cmdLine.split(' ')[0];
  if (!files.includes(exe)) {
    files.unshift(exe);
  }
  const externalDLLs = (query.get('external') || '').split(',');
  const relocate = query.has('relocate');
  const params: URLParams = { dir, cmdLine, externalDLLs, files, relocate };
  return params;
}

export async function load(host: Host) {
  const params = parseURL();
  if (!params) {
    throw new Error('invalid URL params');
  }

  const fileset = await fetchFileSet(params.files, params.dir);

  await wasm.default(new URL('wasm.wasm', document.location.href));

  const storageKey = (params.dir ?? '') + params.cmdLine.split(' ')[0];
  const emu = new Emulator(host, fileset, storageKey, params.externalDLLs);
  emu.startExe(params.cmdLine, params.relocate ?? false);
  return emu;
}
