/**
 * Deploy entry point for Soccer Pinball 98 running on retrowin32/wasm.
 *
 * Preloads the whole game directory (listed in game/manifest.json) into the
 * emulator's in-memory filesystem, boots winpin.exe, and mounts its DirectDraw
 * canvas.  Keyboard and audio are wired inside emulator.ts.
 */

import * as wasm from './glue/pkg/glue';
import { Emulator, FileSet, Host, Status } from './emulator';

/** Where the game files and manifest are served from, relative to this page. */
const GAME_DIR = 'game/';
/** Virtual working directory the game starts in (it later chdirs ".."). */
const INITIAL_CWD = 'soccer98';
/** Command line: winpin.exe resolved relative to INITIAL_CWD. */
const CMDLINE = 'winpin.exe';
/** Parallel fetches while preloading. */
const FETCH_CONCURRENCY = 24;

function $(id: string): HTMLElement {
  return document.getElementById(id)!;
}

async function fetchAllFiles(
  paths: string[],
  onProgress: (done: number, total: number) => void,
): Promise<FileSet> {
  const files: FileSet = new Map();
  let done = 0;
  let next = 0;
  async function worker() {
    while (next < paths.length) {
      const i = next++;
      const path = paths[i];
      const resp = await fetch(GAME_DIR + path);
      if (!resp.ok) throw new Error(`failed to load ${path}: ${resp.status}`);
      const bytes = new Uint8Array(await resp.arrayBuffer());
      files.set(path.toLowerCase().replace(/\\/g, '/'), bytes);
      onProgress(++done, paths.length);
    }
  }
  const workers = [];
  for (let i = 0; i < Math.min(FETCH_CONCURRENCY, paths.length); i++) {
    workers.push(worker());
  }
  await Promise.all(workers);
  return files;
}

async function boot() {
  const status = $('status');
  const bar = $('bar');
  const setStatus = (t: string) => (status.textContent = t);

  setStatus('Загрузка списка файлов…');
  const manifest = (await (await fetch(GAME_DIR + 'manifest.json')).json()) as string[];

  setStatus('Загрузка игры…');
  const files = await fetchAllFiles(manifest, (done, total) => {
    const pct = Math.floor((done / total) * 100);
    bar.style.width = `${pct}%`;
    setStatus(`Загрузка игры… ${done}/${total}`);
  });

  setStatus('Инициализация эмулятора…');
  await wasm.default(new URL('wasm.wasm', document.location.href));

  const screen = $('screen');
  const host: Host = {
    onWindowChanged: () => {
      // Mount the (single) game window's canvas into the screen container.
      const win = emu.windows[emu.windows.length - 1];
      if (win && win.canvas.parentElement !== screen) {
        screen.innerHTML = '';
        screen.appendChild(win.canvas);
      }
      $('loading').style.display = 'none';
    },
    onError: (msg) => {
      setStatus('Ошибка: ' + msg);
      $('loading').style.display = 'flex';
      console.error(msg);
    },
    onStdOut: (s) => console.log(s),
    onStopped: (st) => {
      if (st === Status.Exit) console.log('exited', emu.emu.exit_code);
    },
    onEvent: (event) => emu.enqueueEvent(event),
  };

  const emu = new Emulator(host, files, 'soccer98', [], INITIAL_CWD);
  emu.emu.set_tracing_scheme('-');
  emu.startExe(CMDLINE, false);
  emu.start();
}

export function main() {
  boot().catch((e) => {
    $('status').textContent = 'Ошибка: ' + (e.stack ?? e.toString());
    console.error(e);
  });
}
